{\n        return\n      }\n      if (target.closest('.dm-expand-btn')) {\n        return\n      }\n      this.onToggleExpand()\n    },\n  },\n})\n</script>\n\n<style scoped>\n.dm-result-wrapper {\n  border-bottom: 1px solid var(--line_light, #f0f0f0);\n}\n\n.dm-result-item {\n  display: flex;\n  gap: 12px;\n  padding: 10px;\n  cursor: pointer;\n  align-items: center;\n}\n\n.dm-result-cover-box {\n  width: 110px;\n  height: 70px;\n  border-radius: 4px;\n  overflow: hidden;\n  background: #e7e7e7;\n  flex-shrink: 0;\n  position: relative;\n}\n\n.dm-result-cover-box .dm-result-cover {\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n  cursor: pointer;\n}\n\n.dm-result-duration {\n  position: absolute;\n  bottom: 4px;\n  right: 4px;\n  background: rgba(0, 0, 0, 0.7);\n  color: #fff;\n  font-size: 11px;\n  padding: 1px 4px;\n  border-radius: 2px;\n  font-weight: 500;\n}\n\n.dm-result-info {\n  flex: 1;\n  min-width: 0;\n  overflow: hidden;\n}\n\n.dm-result-title {\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--text1, #222);\n  margin-bottom: 6px;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  display: -webkit-box;\n  -webkit-line-clamp: 2;\n  -webkit-box-orient: vertical;\n}\n\n.dm-result-meta {\n  font-size: 12px;\n  color: var(--text3, #999);\n}\n\n.dm-expand-btn {\n  flex-shrink: 0;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 32px;\n  height: 32px;\n  border-radius: 50%;\n  transition: background 0.2s;\n}\n\n.dm-inline-details {\n  background: var(--bg2, #f9f9f9);\n  padding: 10px;\n  border-top: 1px solid var(--line_light, #eee);\n}\n\n.dm-details-loading {\n  text-align: center;\n  color: var(--text3, #999);\n  padding: 20px;\n}\n</style>\n"],"sourceRoot":""}]);
